 1	import * as React from 'react';
 2	import { Button, ButtonVariant, Modal, ModalVariant } from '@patternfly/react-core';
 3	import { DestinationRuleC, K8sGRPCRoute, K8sHTTPRoute, VirtualService } from '../../types/IstioObjects';
 4	import { t } from 'utils/I18nUtils';
 5	
 6	type Props = {
 7	  destinationRules: DestinationRuleC[];
 8	  isOpen: boolean;
 9	  k8sGRPCRoutes: K8sGRPCRoute[];
10	  k8sHTTPRoutes: K8sHTTPRoute[];
11	  onCancel: () => void;
12	  onConfirm: () => void;
13	  virtualServices: VirtualService[];
14	};
15	
16	export const ConfirmDeleteTrafficRoutingModal: React.FunctionComponent<Props> = props => {
17	  function hasAnyPeerAuthn(drs: DestinationRuleC[]): boolean {
18	    return drs.filter(dr => !!dr.hasPeerAuthentication()).length > 0;
19	  }
20	
21	  function getDeleteMessage(): React.ReactNode {
22	    const deleteMessage = t('Are you sure you want to delete ?');
23	    const deleteItems: JSX.Element[] = [];
24	
25	    let i = 0;
26	    let vsMessage =
27	      props.virtualServices.length > 0
28	        ? `VirtualService${props.virtualServices.length > 1 ? 's' : ''}: '${props.virtualServices.map(
29	            vs => vs.metadata.name
30	          )}'`
31	        : '';
32	    deleteItems.push(<div key={`delete_item_${++i}`}>{vsMessage}</div>);
33	
34	    let drMessage =
35	      props.destinationRules.length > 0
36	        ? `DestinationRule${props.destinationRules.length > 1 ? 's' : ''}: '${props.destinationRules.map(
37	            dr => dr.metadata.name
38	          )}'`
39	        : '';
40	    deleteItems.push(<div key={`delete_item_${++i}`}>{drMessage}</div>);
41	
42	    let paMessage =
43	      props.destinationRules.length > 0 && hasAnyPeerAuthn(props.destinationRules)
44	        ? `PeerAuthentication${props.destinationRules.length > 1 ? 's' : ''}: '${props.destinationRules.map(
45	            dr => dr.metadata.name
46	          )}'`
47	        : '';
48	    deleteItems.push(<div key={`delete_item_${++i}`}>{paMessage}</div>);
49	
50	    let k8sHTTPRouteMessage =
51	      props.k8sHTTPRoutes.length > 0
52	        ? `K8s HTTPRoute${props.k8sHTTPRoutes.length > 1 ? 's' : ''}: '${props.k8sHTTPRoutes.map(
53	            k8sr => k8sr.metadata.name
54	          )}'`
55	        : '';
56	    deleteItems.push(<div key={`delete_item_${++i}`}>{k8sHTTPRouteMessage}</div>);
57	
58	    const k8sGRPCRouteMessage =
59	      props.k8sGRPCRoutes.length > 0
60	        ? `K8s GRPCRoute${props.k8sGRPCRoutes.length > 1 ? 's' : ''}: '${props.k8sGRPCRoutes.map(
61	            k8sr => k8sr.metadata.name
62	          )}'`
63	        : '';
64	    deleteItems.push(<div key={`delete_item_${++i}`}>{k8sGRPCRouteMessage}</div>);
65	
66	    return (
67	      <>
68	        <div key="delete_items" style={{ marginBottom: 5 }}>
69	          {deleteMessage}
70	        </div>
71	        {deleteItems}
72	      </>
73	    );
74	  }
75	
76	  return (
77	    <Modal
78	      variant={ModalVariant.small}
79	      title={t('Confirm Delete Traffic Routing ?')}
80	      isOpen={props.isOpen}
81	      onClose={props.onCancel}
82	      data-test="delete-traffic-routing-modal"
83	      actions={[
84	        <Button key="confirm" variant={ButtonVariant.danger} onClick={props.onConfirm} data-test={'confirm-delete'}>
85	            {t('Delete')}
86	        </Button>,
87	        <Button key="cancel" variant={ButtonVariant.secondary} isInline onClick={props.onCancel}>
88	            {t('Cancel')}
89	        </Button>
90	      ]}
91	    >
92	      {getDeleteMessage()}
93	    </Modal>
94	  );
95	};

